qry:select.qry:xquery:
for $r in SQL(' select liq19.oi_liquidacion as ID, liq19.c_liquidacion as CODE, liq19.d_titulo as TEXT from liq19_liquidacion as liq19 where liq19.OI_EMPRESA = {%= #SOURCE:@oi_padre%}
{%? (#PARA:@noValidarCerradas='0') {% AND liq19.c_estado=\'C\' %} {% %} %}
{%? (string(#FILTRO:helper-mess/rows/row/@oi_liquidacion)!='') {% and liq19.oi_liquidacion in ({%=string(#FILTRO:helper-mess/rows/row/@oi_liquidacion) %}) %} {% and 1 = 2 %} %} ')/ROWS/ROW

					for $r in SQL('
		select
			liq19.oi_liquidacion as ID,
			liq19.c_liquidacion as CODE,
			liq19.d_titulo as TEXT
		from
			liq19_liquidacion as liq19
		where

			liq19.OI_EMPRESA = {%= #SOURCE:@oi_padre%}   
			{%? 
				(#PARA:@noValidarCerradas='0') 
				{% AND liq19.c_estado=\'C\' %} 
				{% %} 
			%}
	{%? (string(#FILTRO:helper-mess/rows/row/@oi_liquidacion)!='') {% and oi_liquidacion not in ({%=string(#FILTRO:helper-mess/rows/row/@oi_liquidacion) %}) %} {% and 1 = 1 %} %}
 ')/ROWS/ROW
